map.on("load", async () =&gt; {
  const response = await fetch("./tirana_archival_areas_placeholder.geojson");
  const archivalAreas = await response.json();

  map.addSource("archival-areas", {
    type: "geojson",
    data: archivalAreas
  });

  map.addLayer({
    id: "archival-areas-fill",
    type: "fill",
    source: "archival-areas",
    paint: {
      "fill-color": ["get", "color"],
      "fill-opacity": 0.35
    }
  });

  map.addLayer({
    id: "archival-areas-outline",
    type: "line",
    source: "archival-areas",
    paint: {
      "line-color": ["get", "color"],
      "line-width": 2
    }
  });

  map.on("click", "archival-areas-fill", (e) =&gt; {
    const props = e.features[0].properties;

    const html = `
      &lt;h3&gt;${props.name}&lt;/h3&gt;
      &lt;p&gt;&lt;strong&gt;Period:&lt;/strong&gt; ${props.period}&lt;/p&gt;
      &lt;p&gt;&lt;strong&gt;Category:&lt;/strong&gt; ${props.category}&lt;/p&gt;
    `;

    new maplibregl.Popup()
      .setLngLat(e.lngLat)
      .setHTML(html)
      .addTo(map);
  });
});

